const configureDashboardRuntimeProfile = () => {
  if (!isDev && !EARLY_DASHBOARD_MULTI_INSTANCE) return;

  try {
    const profileBaseName = isDev
      ? `admin-app-dashboard-dev-${EARLY_DASHBOARD_INSTANCE_ID}`
      : `${app.getName()}-dashboard-${EARLY_DASHBOARD_INSTANCE_ID}`;
    const profileRoot = isDev ? os.tmpdir() : app.getPath('appData');
    const userDataDir = path.join(profileRoot, profileBaseName);
    const sessionDataDir = path.join(userDataDir, 'session');

    fs.mkdirSync(sessionDataDir, { recursive: true });
    app.setPath('userData', userDataDir);
    app.setPath('sessionData', sessionDataDir);

    if (isDev) {
      app.commandLine.appendSwitch('disable-gpu-shader-disk-cache');
      app.commandLine.appendSwitch('disable-http-cache');
    }
  } catch (error) {
    console.warn('[Dashboard] Failed to set runtime profile path:', error?.message || error);
  }
};

