const normalizeVersionString = (value) => String(value || '').trim().replace(/^v/i, '');

const compareVersions = (left, right) => {
  const a = normalizeVersionString(left).split('.').map((item) => Number(item) || 0);
  const b = normalizeVersionString(right).split('.').map((item) => Number(item) || 0);
  const length = Math.max(a.length, b.length);
  for (let i = 0; i < length; i += 1) {
    const diff = (a[i] || 0) - (b[i] || 0);
    if (diff > 0) return 1;
    if (diff < 0) return -1;
  }
  return 0;
};

const normalizeGithubReleaseInfo = (payload = {}) => ({
  version: normalizeVersionString(payload.tag_name || payload.name || ''),
  rawVersion: String(payload.tag_name || payload.name || '').trim(),
  releaseName: String(payload.name || payload.tag_name || '').trim(),
  publishedAt: payload.published_at || payload.created_at || null,
  htmlUrl: String(payload.html_url || UPDATER_RELEASE_PAGE || '').trim(),
});

const fetchLatestGithubRelease = async () => {
  if (!UPDATER_FEED_CONFIG || !UPDATER_FEED_CONFIG.owner || !UPDATER_FEED_CONFIG.repo) {
    throw new Error('Chua cau hinh GitHub repository cho dashboard web updater.');
  }

  const apiBaseUrl = `https://api.github.com/repos/${UPDATER_FEED_CONFIG.owner}/${UPDATER_FEED_CONFIG.repo}`;
  const headers = {
    'User-Agent': 'admin-app-dashboard-web-updater',
    Accept: 'application/vnd.github+json',
  };

  if (UPDATER_FEED_CONFIG.token) {
    headers.Authorization = `Bearer ${UPDATER_FEED_CONFIG.token}`;
  }

  const latestResponse = await fetch(`${apiBaseUrl}/releases/latest`, { headers });
  if (latestResponse.ok) {
    return normalizeGithubReleaseInfo(await latestResponse.json());
  }

  if (latestResponse.status === 404) {
    const releasesResponse = await fetch(`${apiBaseUrl}/releases?per_page=1`, { headers });

    if (releasesResponse.ok) {
      const releases = await releasesResponse.json();
      if (Array.isArray(releases) && releases.length > 0) {
        return normalizeGithubReleaseInfo(releases[0]);
      }
      throw new Error('GitHub repository chua co Release nao de kiem tra cap nhat. Hay tao release dau tien tren GitHub.');
    }

    if (releasesResponse.status === 404) {
      const tokenHint = UPDATER_FEED_CONFIG.token ? '' : ' Neu repo private, them GH_TOKEN hoac GITHUB_TOKEN.';
      throw new Error(`Khong tim thay repository/release GitHub. Kiem tra UPDATER_GITHUB_OWNER, UPDATER_GITHUB_REPO.${tokenHint}`);
    }

    throw new Error(`GitHub Releases API HTTP ${releasesResponse.status}`);
  }

  if (latestResponse.status === 401 || latestResponse.status === 403) {
    throw new Error(`GitHub Releases API HTTP ${latestResponse.status}. Kiem tra token GitHub hoac gioi han rate limit.`);
  }

  throw new Error(`GitHub Releases API HTTP ${latestResponse.status}`);
};

