const getLicenseUpdateAccessState = async () => {
  try {
    const machineId = getMachineId();
    const license = await License.findOne({ machineId, isActive: true }).sort({ activatedAt: -1, date: -1 }).lean();
    if (!license) {
      return {
        licenseAllowsUpdates: false,
        licenseUpdateMessage: 'Khong tim thay key dang kich hoat tren may nay.',
        licenseClientName: '',
        licenseKey: '',
      };
    }

    if (license.allowGithubUpdates === false) {
      return {
        licenseAllowsUpdates: false,
        licenseUpdateMessage: 'Key hien tai khong duoc phep cap nhat phien ban moi tu GitHub.',
        licenseClientName: String(license.clientName || ''),
        licenseKey: String(license.key || ''),
      };
    }

    return {
      licenseAllowsUpdates: true,
      licenseUpdateMessage: '',
      licenseClientName: String(license.clientName || ''),
      licenseKey: String(license.key || ''),
    };
  } catch (error) {
    return {
      licenseAllowsUpdates: false,
      licenseUpdateMessage: 'Khong the kiem tra quyen cap nhat cua key: ' + error.message,
      licenseClientName: '',
      licenseKey: '',
    };
  }
};

const ensureLicenseAllowsGithubUpdate = async () => {
  const licenseState = await getLicenseUpdateAccessState();
  if (licenseState.licenseAllowsUpdates) {
    return { allowed: true, state: licenseState };
  }

  updateUpdaterState({
    checking: false,
    downloading: false,
    downloaded: false,
    progress: 0,
    error: licenseState.licenseUpdateMessage,
    message: licenseState.licenseUpdateMessage,
    lastCheckedAt: Date.now(),
    ...licenseState,
  });

  return { allowed: false, state: licenseState };
};

const checkWebOnlyGithubUpdate = async () => {
  const licenseAccess = await ensureLicenseAllowsGithubUpdate();
  if (!licenseAccess.allowed) {
    return { success: false, message: licenseAccess.state.licenseUpdateMessage, data: buildUpdateStatePayload(licenseAccess.state), manual: true };
  }

  updateUpdaterState({
    ...licenseAccess.state,
    checking: true,
    available: false,
    downloading: false,
    downloaded: false,
    progress: 0,
    error: '',
    message: 'Dang kiem tra release moi tren GitHub...',
    isWebOnly: true,
    manualUpdate: true,
    releasePage: UPDATER_RELEASE_PAGE,
    lastCheckedAt: Date.now(),
  });

  try {
    const latest = await fetchLatestGithubRelease();
    const currentVersion = normalizeVersionString(app.getVersion());
    const hasUpdate = latest.version && compareVersions(latest.version, currentVersion) > 0;
    const message = hasUpdate
      ? `Da tim thay release moi ${latest.version}. Dashboard web can pull/build/redeploy tren server.`
      : `Dashboard web dang o ban moi nhat (${currentVersion}).`;

    updateUpdaterState({
      checking: false,
      available: hasUpdate,
      downloading: false,
      downloaded: false,
      progress: 0,
      latestVersion: latest.version || currentVersion,
      releaseName: latest.releaseName || latest.tagName || '',
      releaseDate: latest.releaseDate || '',
      releaseNotes: formatReleaseNotes(latest.releaseNotes),
      message,
      error: '',
      isWebOnly: true,
      manualUpdate: true,
      releasePage: latest.releasePage || UPDATER_RELEASE_PAGE,
      lastCheckedAt: Date.now(),
    });

    return { success: true, message, data: buildUpdateStatePayload(), manual: true };
  } catch (error) {
    const msg = normalizeUpdaterErrorMessage(error);
    updateUpdaterState({
      checking: false,
      downloading: false,
      downloaded: false,
      progress: 0,
      error: msg,
      message: `Khong the kiem tra release GitHub: ${msg}`,
      isWebOnly: true,
      manualUpdate: true,
      releasePage: UPDATER_RELEASE_PAGE,
      lastCheckedAt: Date.now(),
    });
    return { success: false, message: msg, data: buildUpdateStatePayload(), manual: true };
  }
};

const sendUpdateState = () => {
  const payload = buildUpdateStatePayload();

  emitDashboardUiEvent('update-status', payload);
  if (payload.message) {
    emitDashboardUiEvent('update-message', payload.message);
  }
};

const updateUpdaterState = (patch = {}) => {
  updateState = {
    ...updateState,
    ...patch,
    currentVersion: app.getVersion(),
    isPortable: isPortableBuild(),
    isWebOnly: DASHBOARD_WEB_ONLY,
    manualUpdate: DASHBOARD_WEB_ONLY || isPortableBuild() || !canUseNativeAutoUpdater(),
    releasePage: patch.releasePage || updateState.releasePage || UPDATER_RELEASE_PAGE,
  };
  sendUpdateState();
};

const clampNumber = (value, min, max, fallback) => {
  const num = Number(value);
  if (!Number.isFinite(num)) return fallback;
  return Math.min(max, Math.max(min, num));
};

const toBool = (value, fallback = false) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') {
    if (value === 'true') return true;
    if (value === 'false') return false;
  }
  return fallback;
};

const sanitizeTimeValue = (value, fallback) => {
  const raw = String(value || '').trim();
  if (/^\d{2}:\d{2}$/.test(raw)) {
    const hh = Number(raw.slice(0, 2));
    const mm = Number(raw.slice(3, 5));
    if (hh >= 0 && hh < 24 && mm >= 0 && mm < 60) return raw;
  }
  return fallback;
};

const timeToMinutes = (timeValue) => {
  const safe = sanitizeTimeValue(timeValue, '');
  if (!safe) return null;
  return Number(safe.slice(0, 2)) * 60 + Number(safe.slice(3, 5));
};

const isInsideWindow = (currentMinutes, startMinutes, endMinutes) => {
  if (startMinutes === null || endMinutes === null || startMinutes === endMinutes) return false;
  if (startMinutes < endMinutes) return currentMinutes >= startMinutes && currentMinutes < endMinutes;
  return currentMinutes >= startMinutes || currentMinutes < endMinutes;
};

const getCurrentMinutesByTimezone = (timezone) => {
  try {
    const formatter = new Intl.DateTimeFormat('en-GB', {
      timeZone: timezone || 'Asia/Ho_Chi_Minh',
      hour12: false,
      hour: '2-digit',
      minute: '2-digit',
    });
    const parts = formatter.formatToParts(new Date());
    const hh = Number(parts.find((p) => p.type === 'hour')?.value || '0');
    const mm = Number(parts.find((p) => p.type === 'minute')?.value || '0');
    return hh * 60 + mm;
  } catch (_) {
    const now = new Date();
    return now.getHours() * 60 + now.getMinutes();
  }
};

const sanitizeResourceOptimizer = (input = {}) => ({
  enabled: toBool(input.enabled, DEFAULT_RESOURCE_OPTIMIZER.enabled),
  checkIntervalSec: clampNumber(input.checkIntervalSec, 5, 300, DEFAULT_RESOURCE_OPTIMIZER.checkIntervalSec),
  highCpuPercent: clampNumber(input.highCpuPercent, 40, 100, DEFAULT_RESOURCE_OPTIMIZER.highCpuPercent),
  highRamPercent: clampNumber(input.highRamPercent, 40, 100, DEFAULT_RESOURCE_OPTIMIZER.highRamPercent),
  hiddenFps: clampNumber(input.hiddenFps, 1, 60, DEFAULT_RESOURCE_OPTIMIZER.hiddenFps),
  clearCacheCooldownSec: clampNumber(input.clearCacheCooldownSec, 30, 3600, DEFAULT_RESOURCE_OPTIMIZER.clearCacheCooldownSec),
});

const sanitizeMaintenanceSchedule = (input = {}) => ({
  enabled: toBool(input.enabled, DEFAULT_MAINTENANCE_SCHEDULE.enabled),
  startTime: sanitizeTimeValue(input.startTime, DEFAULT_MAINTENANCE_SCHEDULE.startTime),
  endTime: sanitizeTimeValue(input.endTime, DEFAULT_MAINTENANCE_SCHEDULE.endTime),
  timezone: String(input.timezone || DEFAULT_MAINTENANCE_SCHEDULE.timezone).trim() || DEFAULT_MAINTENANCE_SCHEDULE.timezone,
  applySystem: toBool(input.applySystem, DEFAULT_MAINTENANCE_SCHEDULE.applySystem),
  applyDeposit: toBool(input.applyDeposit, DEFAULT_MAINTENANCE_SCHEDULE.applyDeposit),
  applyWithdraw: toBool(input.applyWithdraw, DEFAULT_MAINTENANCE_SCHEDULE.applyWithdraw),
  runtimeActive: toBool(input.runtimeActive, DEFAULT_MAINTENANCE_SCHEDULE.runtimeActive),
});

const mergeSettingsWithDefaults = (raw = {}) => ({
  ...(raw || {}),
  resourceOptimizer: sanitizeResourceOptimizer({
    ...DEFAULT_RESOURCE_OPTIMIZER,
    ...(raw && raw.resourceOptimizer ? raw.resourceOptimizer : {}),
  }),
  maintenanceSchedule: sanitizeMaintenanceSchedule({
    ...DEFAULT_MAINTENANCE_SCHEDULE,
    ...(raw && raw.maintenanceSchedule ? raw.maintenanceSchedule : {}),
  }),
});

const collectSystemStats = () => {
  const currentCpus = os.cpus();
  let idle = 0;
  let total = 0;

  for (let i = 0; i < currentCpus.length; i += 1) {
    const cpu = currentCpus[i];
    const prevCpu = previousCpus[i] || cpu;
    for (const type in cpu.times) {
      total += cpu.times[type] - prevCpu.times[type];
    }
    idle += cpu.times.idle - prevCpu.times.idle;
  }
  previousCpus = currentCpus;

  const cpuPercent = total === 0 ? 0 : (1 - idle / total) * 100;
  const totalMem = os.totalmem();
  const usedMem = totalMem - os.freemem();
  const memPercent = (usedMem / totalMem) * 100;

  latestSystemStats = {
    cpu: Number(cpuPercent.toFixed(1)),
    mem: Number(memPercent.toFixed(1)),
    totalMem: `${(totalMem / 1024 / 1024 / 1024).toFixed(2)} GB`,
    usedMem: `${(usedMem / 1024 / 1024 / 1024).toFixed(2)} GB`,
    uptime: `${(os.uptime() / 3600).toFixed(1)} gio`,
  };
  return latestSystemStats;
};

const sendSystemStats = () => {
  const stats = collectSystemStats();
  emitDashboardUiEvent('system-stats', stats);
};

const applyWindowFrameRatePolicy = () => {
  if (!mainWindow || mainWindow.isDestroyed()) return;
  const wc = mainWindow.webContents;
  const targetFps = (mainWindow.isMinimized() || !mainWindow.isVisible())
    ? Number(resourceOptimizerConfig.hiddenFps)
    : 60;
  try {
    if (typeof wc.setBackgroundThrottling === 'function') wc.setBackgroundThrottling(true);
    if (typeof wc.setFrameRate === 'function') wc.setFrameRate(targetFps);
  } catch (_) {}
};

const optimizeResources = async (reason = 'manual') => {
  applyWindowFrameRatePolicy();

  let cacheCleared = false;
  const now = Date.now();
  const cooldownMs = Number(resourceOptimizerConfig.clearCacheCooldownSec) * 1000;
  if (now - lastCacheClearAt >= cooldownMs) {
    try {
      await session.defaultSession.clearCache();
      lastCacheClearAt = now;
      cacheCleared = true;
    } catch (error) {
      sendLog('WARN', `[Optimizer] clearCache failed: ${error.message}`);
    }
  }

  let gcTriggered = false;
  try {
    if (typeof global.gc === 'function') {
      global.gc();
      gcTriggered = true;
    }
  } catch (_) {}

  sendLog(
    'WARN',
    `[Optimizer] Triggered (${reason}) CPU=${latestSystemStats.cpu}% RAM=${latestSystemStats.mem}% cacheCleared=${cacheCleared} gc=${gcTriggered}`,
  );

  return { cacheCleared, gcTriggered, stats: latestSystemStats };
};

const runResourceOptimizerCycle = async () => {
  if (!resourceOptimizerConfig.enabled) return;
  applyWindowFrameRatePolicy();

  const cpuOver = Number(latestSystemStats.cpu) >= Number(resourceOptimizerConfig.highCpuPercent);
  const ramOver = Number(latestSystemStats.mem) >= Number(resourceOptimizerConfig.highRamPercent);
  if (!cpuOver && !ramOver) return;

  await optimizeResources('threshold');
};

const configureResourceOptimizer = (configInput = null) => {
  if (configInput) {
    resourceOptimizerConfig = sanitizeResourceOptimizer(configInput);
  }

  if (resourceOptimizerInterval) {
    clearInterval(resourceOptimizerInterval);
    resourceOptimizerInterval = null;
  }

  if (!resourceOptimizerConfig.enabled) return;

  const intervalMs = Number(resourceOptimizerConfig.checkIntervalSec) * 1000;
  resourceOptimizerInterval = setInterval(() => {
    runResourceOptimizerCycle().catch((error) => {
      sendLog('WARN', `[Optimizer] cycle failed: ${error.message}`);
    });
  }, intervalMs);
};

const evaluateMaintenanceSchedule = async () => {
  if (mongoose.connection.readyState !== 1) return;

  const doc = await Setting.findOne({}).lean();
  const merged = mergeSettingsWithDefaults(doc || {});
  const schedule = merged.maintenanceSchedule;

  if (!schedule.enabled) {
    if (schedule.runtimeActive) {
      const disablePatch = { 'maintenanceSchedule.runtimeActive': false };
      if (schedule.applySystem) disablePatch.maintenanceSystem = false;
      if (schedule.applyDeposit) disablePatch.maintenanceDeposit = false;
      if (schedule.applyWithdraw) disablePatch.maintenanceWithdraw = false;
      await Setting.findOneAndUpdate({}, { $set: disablePatch }, { upsert: true });
      sendLog('INFO', '[MaintenanceSchedule] Disabled and restored manual maintenance flags.');
    }
    return;
  }

  const startMinutes = timeToMinutes(schedule.startTime);
  const endMinutes = timeToMinutes(schedule.endTime);
  const currentMinutes = getCurrentMinutesByTimezone(schedule.timezone);
  const inWindow = isInsideWindow(currentMinutes, startMinutes, endMinutes);

  if (inWindow && !schedule.runtimeActive) {
    const enablePatch = { 'maintenanceSchedule.runtimeActive': true };
    if (schedule.applySystem) enablePatch.maintenanceSystem = true;
    if (schedule.applyDeposit) enablePatch.maintenanceDeposit = true;
    if (schedule.applyWithdraw) enablePatch.maintenanceWithdraw = true;
    await Setting.findOneAndUpdate({}, { $set: enablePatch }, { upsert: true });
    sendLog('INFO', `[MaintenanceSchedule] Activated ${schedule.startTime}-${schedule.endTime} (${schedule.timezone}).`);
    return;
  }

  if (!inWindow && schedule.runtimeActive) {
    const disablePatch = { 'maintenanceSchedule.runtimeActive': false };
    if (schedule.applySystem) disablePatch.maintenanceSystem = false;
    if (schedule.applyDeposit) disablePatch.maintenanceDeposit = false;
    if (schedule.applyWithdraw) disablePatch.maintenanceWithdraw = false;
    await Setting.findOneAndUpdate({}, { $set: disablePatch }, { upsert: true });
    sendLog('INFO', `[MaintenanceSchedule] Deactivated outside ${schedule.startTime}-${schedule.endTime}.`);
  }
};

const sanitizeSettingsPayload = (payload = {}) => {
  const update = { ...(payload || {}) };
  if (update.resourceOptimizer) {
    update.resourceOptimizer = sanitizeResourceOptimizer(update.resourceOptimizer);
  }
  if (update.maintenanceSchedule) {
    const cleanSchedule = sanitizeMaintenanceSchedule(update.maintenanceSchedule);
    delete cleanSchedule.runtimeActive;
    update.maintenanceSchedule = cleanSchedule;
  }
  return update;
};

const refreshRuntimeConfig = async () => {
  if (mongoose.connection.readyState !== 1) return;
  const settings = await Setting.findOne({}).lean();
  const merged = mergeSettingsWithDefaults(settings || {});
  configureResourceOptimizer(merged.resourceOptimizer);
  await evaluateMaintenanceSchedule();
};

const formatReleaseNotes = (notes) => {
  if (!notes) return '';
  if (typeof notes === 'string') return notes;
  if (Array.isArray(notes)) {
    return notes
      .map((item) => {
        if (typeof item === 'string') return item;
        if (item && typeof item.note === 'string') return item.note;
        return '';
      })
      .filter(Boolean)
      .join('\n\n');
  }
  return '';
};

const normalizeUpdaterErrorMessage = (error) => {
  const raw = error?.message || String(error || '');
  const lowerRaw = raw.toLowerCase();

  if (
    lowerRaw.includes('cannot parse releases feed') ||
    lowerRaw.includes('unable to find latest version on github') ||
    lowerRaw.includes('err_updater_latest_version_not_found') ||
    lowerRaw.includes('httperror: 406')
  ) {
    return `${UPDATER_PUBLISH_HINT} Mo trang Releases de kiem tra: ${UPDATER_RELEASE_PAGE}`;
  }

  if (
    lowerRaw.includes('err_updater_channel_file_not_found') ||
    lowerRaw.includes('cannot find latest.yml')
  ) {
    return `Da tim thay release nhung thieu latest.yml hoac file cai dat. ${UPDATER_PUBLISH_HINT}`;
  }

  return raw;
};

const ensureAutoUpdater = () => {
  if (autoUpdater) return autoUpdater;
  try {
    const updaterModule = require('electron-updater');
    const candidate = updaterModule && updaterModule.autoUpdater;
    if (!candidate || typeof candidate.checkForUpdates !== 'function') {
      throw new Error('electron-updater autoUpdater is unavailable');
    }
    autoUpdater = candidate;
    autoUpdaterInitError = '';
    if (UPDATER_FEED_CONFIG && typeof autoUpdater.setFeedURL === 'function') {
      try {
        autoUpdater.setFeedURL(UPDATER_FEED_CONFIG);
      } catch (feedError) {
        console.warn('[Updater] setFeedURL failed:', feedError?.message || feedError);
      }
    }
    return autoUpdater;
  } catch (error) {
    autoUpdater = null;
    autoUpdaterInitError = error?.message || String(error);
    console.warn('[Updater] electron-updater unavailable:', autoUpdaterInitError);
    return null;
  }
};

const setupAutoUpdater = () => {
  if (updaterReady) return;
  const updater = ensureAutoUpdater();
  if (!updater) {
    updateUpdaterState({
      checking: false,
      downloading: false,
      downloaded: false,
      progress: 0,
      error: autoUpdaterInitError || 'electron-updater unavailable',
      message: 'Khong the khoi tao bo cap nhat tu dong trong moi truong hien tai.',
      lastCheckedAt: Date.now(),
    });
    return;
  }

  updaterReady = true;

  updater.autoDownload = false;
  updater.autoInstallOnAppQuit = true;

  updater.on('checking-for-update', () => {
    updateUpdaterState({
      checking: true,
      available: false,
      downloading: false,
      downloaded: false,
      progress: 0,
      error: '',
      message: 'Dang kiem tra ban cap nhat...',
      lastCheckedAt: Date.now(),
    });
  });

  updater.on('update-available', (info) => {
    updateUpdaterState({
      checking: false,
      available: true,
      downloaded: false,
      downloading: false,
      progress: 0,
      latestVersion: info?.version || null,
      releaseName: info?.releaseName || '',
      releaseDate: info?.releaseDate || '',
      releaseNotes: formatReleaseNotes(info?.releaseNotes),
      message: `Da tim thay ban moi ${info?.version || ''}.`,
      error: '',
    });
  });

  updater.on('update-not-available', (info) => {
    updateUpdaterState({
      checking: false,
      available: false,
      downloading: false,
      downloaded: false,
      progress: 0,
      latestVersion: info?.version || app.getVersion(),
      message: `Dang o ban moi nhat (${app.getVersion()}).`,
      error: '',
      lastCheckedAt: Date.now(),
    });
  });

  updater.on('download-progress', (progress) => {
    const percent = Number(progress?.percent || 0);
    updateUpdaterState({
      downloading: true,
      progress: Number.isFinite(percent) ? Math.max(0, Math.min(100, Math.round(percent))) : 0,
      message: `Dang tai ban cap nhat... ${Math.round(percent || 0)}%`,
      error: '',
    });
  });

  updater.on('update-downloaded', (info) => {
    updateUpdaterState({
      checking: false,
      available: true,
      downloading: false,
      downloaded: true,
      progress: 100,
      latestVersion: info?.version || updateState.latestVersion,
      releaseName: info?.releaseName || updateState.releaseName,
      releaseDate: info?.releaseDate || updateState.releaseDate,
      releaseNotes: formatReleaseNotes(info?.releaseNotes) || updateState.releaseNotes,
      message: isPortableBuild()
        ? 'Da tai thong tin ban moi. Ban portable can tai file moi tu Releases.'
        : 'Da tai xong. Bam Cai dat de cap nhat va khoi dong lai.',
      error: '',
    });
  });

  updater.on('error', (error) => {
    const msg = normalizeUpdaterErrorMessage(error);
    updateUpdaterState({
      checking: false,
      downloading: false,
      error: msg,
      message: `Khong the cap nhat tu dong: ${msg}`,
      lastCheckedAt: Date.now(),
    });
  });
};
// --- HELPERS FOR CHILD PROCESSES / EMBEDDED SERVERS ---
const normalizePort = (value, fallback) => {
  const num = Number(value);
  return Number.isInteger(num) && num > 0 && num < 65536 ? num : fallback;
};

const isTruthyEnv = (value) => /^(1|true|yes|on)$/i.test(String(value || '').trim());

const getTaixiuBackendBaseUrl = () => {
  const host = String(process.env.TAIXIU_BACKEND_HOST || '127.0.0.1').trim() || '127.0.0.1';
  const port = normalizePort(process.env.TAIXIU_BACKEND_PORT, TAIXIU_BACKEND_PORT);
  return `http://${host}:${port}`;
};

const requestTaixiuBackend = async (endpoint, options = {}) => {
  const timeoutMs = Number.isFinite(Number(options.timeoutMs)) ? Number(options.timeoutMs) : 8000;
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const method = String(options.method || 'GET').toUpperCase();
    const url = `${getTaixiuBackendBaseUrl()}${endpoint}`;
    const hasBody = options.body && typeof options.body === 'object';
    const response = await fetch(url, {
      method,
      headers: hasBody ? { 'Content-Type': 'application/json' } : undefined,
      body: hasBody ? JSON.stringify(options.body) : undefined,
      signal: controller.signal,
    });

    const text = await response.text();
    let data = {};
    if (text) {
      try {
        data = JSON.parse(text);
      } catch (_) {
        data = { message: text };
      }
    }

    if (!response.ok) {
      const msg = data?.message || data?.msg || `HTTP ${response.status}`;
      throw new Error(msg);
    }

    return data;
  } catch (error) {
    if (error && error.name === 'AbortError') {
      throw new Error('TaiXiu backend request timeout');
    }

    const causeCode = error?.cause?.code || error?.code;
    const canRetry = !options.__retriedAfterStart && causeCode === 'ECONNREFUSED';
    if (canRetry) {
      try {
        await startTaixiuBackend();
        await new Promise((resolve) => setTimeout(resolve, 800));
        return await requestTaixiuBackend(endpoint, { ...options, __retriedAfterStart: true });
      } catch (_startErr) {
        const baseUrl = getTaixiuBackendBaseUrl();
        throw new Error(`Khong ket noi duoc TaiXiu backend (${baseUrl}). Hay khoi dong server TaiXiu Backend.`);
      }
    }

    if (causeCode === 'ECONNREFUSED') {
      const baseUrl = getTaixiuBackendBaseUrl();
      throw new Error(`Khong ket noi duoc TaiXiu backend (${baseUrl}). Hay khoi dong server TaiXiu Backend.`);
    }

    throw error;
  } finally {
    clearTimeout(timer);
  }
};

const createInProcessHandle = (name, server) => ({
  type: 'in-process',
  name,
  server,
  exitCode: null,
});

const safeKill = (proc) => {
  if (!proc) return;
  try {
    if (proc.type === 'in-process' && proc.server && typeof proc.server.close === 'function') {
      proc.server.close();
      proc.exitCode = 0;
      return;
    }

    if (process.platform === 'win32') {
      execSync(`taskkill /PID ${proc.pid} /T /F`, { stdio: 'ignore' });
    } else {
      proc.kill('SIGTERM');
    }
  } catch (e) {
    console.warn('[Dashboard] Error killing process:', e.message);
  }
};

const stopManagedProcess = async (proc) => {
  if (!proc || proc.exitCode !== null) return;

  if (proc.type === 'in-process' && proc.server && typeof proc.server.close === 'function') {
    await new Promise((resolve) => {
      try {
        proc.server.close(() => resolve());
      } catch (_) {
        resolve();
      }
    });
    proc.exitCode = 0;
    return;
  }

  safeKill(proc);
};

const startStaticSpaServer = ({
  name,
  distDir,
  port,
  mountApi,
}) => new Promise((resolve, reject) => {
  const appInstance = express();

  if (typeof mountApi === 'function') {
    mountApi(appInstance);
  }

  appInstance.use(express.static(distDir));
  appInstance.get(/.*/i, (req, res) => {
    res.sendFile(path.join(distDir, 'index.html'), (err) => {
      if (err && !res.headersSent) {
        res.status(500).send('Internal Server Error');
      }
    });
  });

  const server = appInstance.listen(port, '0.0.0.0', () => {
    console.log(`[${name}] running on http://localhost:${port}`);
    resolve(server);
  });

  server.on('error', (error) => {
    reject(error);
  });
});
