const toBase64Url = (buf) => Buffer.from(buf).toString('base64url');
const fromBase64Url = (str) => Buffer.from(String(str || ''), 'base64url');
const gameAuthKey = () => crypto.createHash('sha256').update(String(GAME_AUTH_SECRET)).digest();

const encryptGameUrlToken = (payload) => {
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv('aes-256-gcm', gameAuthKey(), iv);
  const body = Buffer.from(JSON.stringify(payload), 'utf8');
  const encrypted = Buffer.concat([cipher.update(body), cipher.final()]);
  const tag = cipher.getAuthTag();
  return `${toBase64Url(iv)}.${toBase64Url(tag)}.${toBase64Url(encrypted)}`;
};

const decryptGameUrlToken = (token) => {
  const parts = String(token || '').split('.');
  if (parts.length !== 3) throw new Error('Malformed encrypted token');
  const iv = fromBase64Url(parts[0]);
  const tag = fromBase64Url(parts[1]);
  const encrypted = fromBase64Url(parts[2]);
  const decipher = crypto.createDecipheriv('aes-256-gcm', gameAuthKey(), iv);
  decipher.setAuthTag(tag);
  const plain = Buffer.concat([decipher.update(encrypted), decipher.final()]);
  return JSON.parse(plain.toString('utf8'));
};

const issueGameSessionToken = (account) => {
  const token = crypto.randomBytes(32).toString('hex');
  gameSessionStore.set(token, {
    userId: account.userId,
    expiresAt: Date.now() + GAME_SESSION_TTL_MS,
  });
  return token;
};
const parseGameUserId = (value) => {
  const raw = String(value == null ? '' : value).trim();
  if (!raw) return null;
  const matched = raw.match(/\d+/);
  if (!matched) return null;
  const parsed = Number(matched[0]);
  if (!Number.isInteger(parsed) || parsed <= 0) return null;
  return parsed;
};

const resolveGameUserId = (reqBody = {}) => {
  const directUserId = parseGameUserId(reqBody.userId ?? reqBody.id);
  if (directUserId) return directUserId;

  const sessionToken = String(reqBody.sessionToken || '').trim();
  if (!sessionToken) return null;
  const session = gameSessionStore.get(sessionToken);
  if (!session || Number(session.expiresAt || 0) <= Date.now()) {
    if (session) gameSessionStore.delete(sessionToken);
    return null;
  }
  return parseGameUserId(session.userId);
};


const createHttpStatusError = (status, message) => {
  const error = new Error(String(message || 'Unknown error'));
  error.status = Number(status) || 500;
  return error;
};

const processGameBetPayload = async (payload = {}) => {
  const game = normalizeSessionGameType(payload.game || 'taixiucao');
  if (!['taixiucao', 'taixiunan'].includes(game)) {
    throw createHttpStatusError(400, 'Game nay khong ho tro API dat cuoc nay');
  }

  if (!isGameSessionRunning(game)) {
    startGameSession(game);
  }

  let session = null;
  for (let i = 0; i < 20; i += 1) {
    session = gameSessions[game] || null;
    if (session && session.running && Number(session.timeLeft || 0) > 0 && typeof session.handleBet === 'function') {
      break;
    }
    // Wait up to ~2s for session init() to complete on first startup.
    await new Promise((resolve) => setTimeout(resolve, 100));
  }

  if (!session || typeof session.handleBet !== 'function' || Number(session.timeLeft || 0) <= 0) {
    throw createHttpStatusError(503, 'Session game dang khoi dong, vui long thu lai');
  }

  const type = String(payload.type || '').trim().toLowerCase();
  const allowedTypes = ['tai', 'xiu'];
  if (!allowedTypes.includes(type)) {
    throw createHttpStatusError(400, 'Cua cuoc khong hop le');
  }

  const amountRaw = Number(payload.amount || 0);
  const amount = Number.isFinite(amountRaw) ? Math.floor(amountRaw) : 0;
  if (amount <= 0) {
    throw createHttpStatusError(400, 'So tien cuoc khong hop le');
  }

  const userId = resolveGameUserId(payload || {});
  if (!userId) {
    throw createHttpStatusError(401, 'Khong xac dinh duoc nguoi choi');
  }

  const account = await Account.findOne({ userId });
  if (!account) {
    throw createHttpStatusError(404, 'Khong tim thay tai khoan');
  }

  const oldBalance = Number(account.balance || 0);
  if (oldBalance < amount) {
    throw createHttpStatusError(400, 'So du khong du');
  }

  const accepted = session.handleBet(type, amount, {
    userId,
    username: `User_${userId}`,
  });

  if (!accepted) {
    throw createHttpStatusError(400, 'Da het thoi gian dat cuoc');
  }

  account.balance = oldBalance - amount;
  await account.save();

  await Transaction.create({
    userId,
    amount,
    action: 'game_bet',
    oldBalance,
    newBalance: Number(account.balance || 0),
    description: `Dat cuoc ${type.toUpperCase()} - ${game}`,
  });

  return {
    success: true,
    newBalance: Number(account.balance || 0),
    phase: session.phase,
    sessionId: session.sessionId,
  };
};

const parseBearerToken = (req) => {
  const auth = req.headers && req.headers.authorization;
  if (typeof auth === 'string' && auth.toLowerCase().startsWith('bearer ')) {
    return auth.slice(7).trim();
  }
  const headerToken = req.headers && req.headers['x-cskh-token'];
  if (typeof headerToken === 'string' && headerToken.trim()) return headerToken.trim();
  if (typeof req.query?.token === 'string' && req.query.token.trim()) return req.query.token.trim();
  return '';
};

const requireCskhManageAuth = (req, res, next) => {
  const token = parseBearerToken(req);
  if (!token) {
    return res.status(401).json({ success: false, message: 'Missing CSKH token' });
  }

  const session = cskhTokenStore.get(token);
  if (!session) {
    return res.status(401).json({ success: false, message: 'Invalid CSKH token' });
  }

  if (session.expiresAt <= Date.now()) {
    cskhTokenStore.delete(token);
    return res.status(401).json({ success: false, message: 'CSKH token expired' });
  }

  // Only supervisor/manager can manage CSKH accounts
  if (!['supervisor', 'manager'].includes(session.role)) {
    return res.status(403).json({ success: false, message: 'Permission denied' });
  }

  req.cskhAuth = session;
  next();
};

async function startLandingServer() {
  if (landingServerProcess && landingServerProcess.exitCode === null) {
    console.log('[Dashboard] Landing server already running');
    return;
  }

  console.log('[Dashboard] Starting landing server...');

  if (isDev) {
    const nodeCmd = process.platform === 'win32' ? 'node.exe' : 'node';
    landingServerProcess = spawn(nodeCmd, [path.join(__dirname, '../src/landing-server.js')], {
      cwd: path.join(__dirname, '..'),
      stdio: 'pipe',
      env: { ...process.env, NODE_ENV: 'development' },
    });

    landingServerProcess.stdout.on('data', (data) => console.log('[Landing]', data.toString().trim()));
    landingServerProcess.stderr.on('data', (data) => console.error('[Landing Error]', data.toString().trim()));
    landingServerProcess.on('error', (err) => console.error('[Landing Process Error]', err));
    landingServerProcess.on('exit', (code) => {
      console.log(`[Landing] Process exited with code ${code}`);
      landingServerProcess = null;
    });
    return;
  }

  const landingDistDir = path.join(__dirname, '../landing/dist');
  if (!fs.existsSync(landingDistDir)) {
    throw new Error(`Landing dist not found: ${landingDistDir}. Run build:landing before packaging.`);
  }

  const port = normalizePort(process.env.LANDING_PORT, LANDING_PORT);
  const server = await startStaticSpaServer({
    name: 'Landing',
    distDir: landingDistDir,
    port,
    mountApi: (landingExpress) => {
      landingExpress.get('/api/get-landing-settings', async (_req, res) => {
        try {
          const settings = await LandingSettings.findOne({}).lean();
          if (!settings) {
            return res.json({ success: true, data: { ...LANDING_DEFAULT_SETTINGS } });
          }

          const { _id, __v, createdAt, updatedAt, ...clean } = settings;
          return res.json({ success: true, data: { ...LANDING_DEFAULT_SETTINGS, ...clean } });
        } catch (error) {
          console.error('[Landing API] get-landing-settings error:', error);
          return res.json({ success: true, data: { ...LANDING_DEFAULT_SETTINGS } });
        }
      });
    },
  });

  landingServerProcess = createInProcessHandle('landing', server);
  server.on('close', () => {
    if (landingServerProcess && landingServerProcess.server === server) {
      landingServerProcess.exitCode = 0;
      landingServerProcess = null;
    }
  });
}

