function createGameSessionInstance(gameType) {
  if (!socketIoRef) {
    throw new Error('Socket server chua san sang');
  }

  if (['taixiucao', 'taixiunan'].includes(gameType)) {
    return new GameSession(socketIoRef, gameType);
  }

  if (['aviator', 'baccarat', 'xocdia', 'rongho'].includes(gameType)) {
    return new ExtraGameSession(socketIoRef, gameType);
  }

  throw new Error('Game type khong hop le');
}

function startGameSession(gameType) {
  if (gameSessions[gameType]) return;
  const session = createGameSessionInstance(gameType);
  gameSessions[gameType] = session;
  session.init();
  const pending = pendingForcedSessionResults.get(gameType);
  if (pending && typeof session.setForcedResult === 'function') {
    try {
      session.setForcedResult(pending);
    } catch (error) {
      console.error(`[Error] apply pending forced result ${gameType}:`, error);
    }
  }
}

function stopGameSession(gameType) {
  const session = gameSessions[gameType];
  if (!session) return;
  if (typeof session.stop === 'function') {
    session.stop();
  }
  delete gameSessions[gameType];
}

function isGameSessionRunning(gameType) {
  return !!gameSessions[gameType];
}

async function ensureTradingMarketSession() {
  if (tradingMarketSession) return tradingMarketSession;
  if (tradingMarketInitPromise) return tradingMarketInitPromise;
  if (!socketIoRef) {
    throw new Error('Socket server chua san sang');
  }

  if (mongoose.connection.readyState !== 1) {
    const waitUntil = Date.now() + 10000;
    while (mongoose.connection.readyState !== 1 && Date.now() < waitUntil) {
      // Wait for connectDB() in app bootstrap to complete so market can restore from DB.
      await new Promise((resolve) => setTimeout(resolve, 200));
    }
  }

  tradingMarketInitPromise = (async () => {
    const session = new TradingMarketSession(socketIoRef);
    await session.init();
    tradingMarketSession = session;
    return session;
  })()
    .catch((error) => {
      console.error('[Trading Market] init error:', error);
      throw error;
    })
    .finally(() => {
      tradingMarketInitPromise = null;
    });

  return tradingMarketInitPromise;
}

function stopTradingMarketSession() {
  if (!tradingMarketSession) return;
  try {
    tradingMarketSession.stop();
  } catch (error) {
    console.warn('[Trading Market] stop error:', error?.message || error);
  }
  tradingMarketSession = null;
}

function getTradingMarketSnapshot(limit = TRADING_MARKET_SNAPSHOT_DEFAULT_LIMIT) {
  if (!tradingMarketSession || typeof tradingMarketSession.getSnapshot !== 'function') {
    return null;
  }
  const limitRaw = Number(limit);
  const safeLimit = Number.isFinite(limitRaw)
    ? Math.min(Math.max(Math.floor(limitRaw), 20), 1000)
    : TRADING_MARKET_SNAPSHOT_DEFAULT_LIMIT;
  return tradingMarketSession.getSnapshot(safeLimit);
}

