function normalizeSessionGameType(gameType) {
  const normalized = String(gameType || '').trim().toLowerCase();
  if (!SESSION_GAME_TYPES.includes(normalized)) {
    throw new Error('Game type khong hop le');
  }
  return normalized;
}

function validateForcedPayload(gameType, payload = {}) {
  if (['taixiucao', 'taixiunan'].includes(gameType)) {
    const dice1 = Number(payload.dice1);
    const dice2 = Number(payload.dice2);
    const dice3 = Number(payload.dice3);
    const valid = [dice1, dice2, dice3].every((n) => Number.isInteger(n) && n >= 1 && n <= 6);
    if (!valid) {
      throw new Error('Dice phai la so nguyen tu 1 den 6');
    }
    return { dice1, dice2, dice3 };
  }

  if (gameType === 'aviator') {
    const crashPoint = Number(payload.crashPoint);
    if (!Number.isFinite(crashPoint) || crashPoint < 1.01) {
      throw new Error('crashPoint phai >= 1.01');
    }
    return { crashPoint: Number(crashPoint.toFixed(2)) };
  }

  const outcome = String(payload.outcome || '').trim().toUpperCase();
  const outcomeMap = {
    baccarat: ['PLAYER', 'BANKER', 'TIE'],
    xocdia: ['CHAN', 'LE'],
    rongho: ['DRAGON', 'TIGER', 'TIE'],
  };
  const validOutcomes = outcomeMap[gameType] || [];
  if (!validOutcomes.includes(outcome)) {
    throw new Error(`Ket qua khong hop le cho ${gameType}`);
  }
  return { outcome };
}

async function persistTxForcedResult(gameType, normalizedPayload) {
  if (!['taixiucao', 'taixiunan'].includes(gameType)) return;
  await TxRoomSetting.findOneAndUpdate(
    { roomType: gameType },
    {
      $set: {
        forceResult: {
          ...normalizedPayload,
          updatedAt: new Date(),
        },
      },
    },
    { upsert: true },
  );
}

async function clearPersistedTxForcedResult(gameType) {
  if (!['taixiucao', 'taixiunan'].includes(gameType)) return;
  await TxRoomSetting.updateOne({ roomType: gameType }, { $unset: { forceResult: 1 } });
}

function applyForcedResultToLiveSession(gameType, normalizedPayload) {
  const session = gameSessions[gameType];
  if (!session || typeof session.setForcedResult !== 'function') {
    return false;
  }
  session.setForcedResult(normalizedPayload);
  return true;
}

function getSessionControlSnapshot(gameType) {
  const session = gameSessions[gameType];
  let pending = pendingForcedSessionResults.get(gameType) || null;
  const base = {
    gameType,
    running: !!session,
    phase: session?.phase || 'STOPPED',
    timeLeft: Number(session?.timeLeft || 0),
    sessionId: Number(session?.sessionId || 0),
    pendingForcedResult: pending,
    mode: gameType === 'aviator' ? 'crash' : (['baccarat', 'xocdia', 'rongho'].includes(gameType) ? 'outcome' : 'dice'),
  };

  if (session && typeof session.getControlState === 'function') {
    const state = session.getControlState() || {};
    if (pending && !state.forcedResult) {
      pendingForcedSessionResults.delete(gameType);
      pending = null;
    }
    return {
      ...base,
      ...state,
      pendingForcedResult: pending,
    };
  }

  return base;
}

function sanitizeNonSessionWinRates(raw = {}) {
  const result = { ...NON_SESSION_GAME_WIN_RATE_DEFAULTS };
  Object.entries(raw || {}).forEach(([key, value]) => {
    if (!(key in NON_SESSION_GAME_WIN_RATE_DEFAULTS)) return;
    const n = Number(value);
    if (!Number.isFinite(n)) return;
    result[key] = Math.max(0, Math.min(100, Math.round(n)));
  });
  return result;
}

async function getNonSessionWinRatesFromSettings() {
  const settings = await Setting.findOne({}).lean();
  return sanitizeNonSessionWinRates(settings?.nonSessionWinRates || {});
}

async function shutdownAllChildren(reason = 'unknown') {
  if (isShuttingDown) return;
  isShuttingDown = true;
  console.log(`[Dashboard] Shutdown all children (reason: ${reason})`);

  try { stopTaiXiuSession('taixiucao'); } catch (e) { console.warn('[Shutdown] stop taixiucao session error:', e?.message || e); }
  try { stopTaiXiuSession('taixiunan'); } catch (e) { console.warn('[Shutdown] stop taixiunan session error:', e?.message || e); }
  try { stopGameSession('aviator'); } catch (e) { console.warn('[Shutdown] stop aviator session error:', e?.message || e); }
  try { stopGameSession('baccarat'); } catch (e) { console.warn('[Shutdown] stop baccarat session error:', e?.message || e); }
  try { stopGameSession('xocdia'); } catch (e) { console.warn('[Shutdown] stop xocdia session error:', e?.message || e); }
  try { stopGameSession('rongho'); } catch (e) { console.warn('[Shutdown] stop rongho session error:', e?.message || e); }
  try { stopTradingMarketSession(); } catch (e) { console.warn('[Shutdown] stop trading market session error:', e?.message || e); }
  try { stopExtraGameWebs(); } catch (e) { console.warn('[Shutdown] stop extra games error:', e?.message || e); }
  try { await stopWebgameProcess(); } catch (e) { console.warn('[Shutdown] stop webgame error:', e?.message || e); }
  try { await stopTaixiuBackend(); } catch (e) { console.warn('[Shutdown] stop taixiu backend error:', e?.message || e); }

  try {
    if (taixiuCaoWebProcess && taixiuCaoWebProcess.exitCode === null) safeKill(taixiuCaoWebProcess);
    taixiuCaoWebProcess = null;
  } catch (e) {
    console.warn('[Shutdown] stop taixiu cao web error:', e?.message || e);
  }

  try {
    if (taixiuNanWebProcess && taixiuNanWebProcess.exitCode === null) safeKill(taixiuNanWebProcess);
    taixiuNanWebProcess = null;
  } catch (e) {
    console.warn('[Shutdown] stop taixiu nan web error:', e?.message || e);
  }

  try {
    if (cskhAppProcess && cskhAppProcess.exitCode === null) safeKill(cskhAppProcess);
    cskhAppProcess = null;
  } catch (e) {
    console.warn('[Shutdown] stop cskh app error:', e?.message || e);
  }

  try {
    if (landingServerProcess && landingServerProcess.exitCode === null) safeKill(landingServerProcess);
    landingServerProcess = null;
  } catch (e) {
    console.warn('[Shutdown] stop landing server error:', e?.message || e);
  }

  try {
    if (mainBotService && typeof mainBotService.stop === 'function') {
      Promise.resolve(mainBotService.stop()).catch(() => {});
    }
  } catch (e) {
    console.warn('[Shutdown] stop main bot error:', e?.message || e);
  }

  try {
    if (socketIoRef && typeof socketIoRef.close === 'function') {
      socketIoRef.close();
    }
  } catch (e) {
    console.warn('[Shutdown] close socket.io error:', e?.message || e);
  }

  try {
    if (apiHttpServer && typeof apiHttpServer.close === 'function') {
      apiHttpServer.close();
    }
  } catch (e) {
    console.warn('[Shutdown] close api server error:', e?.message || e);
  }

  try {
    if (mongoose.connection.readyState === 1) {
      mongoose.connection.close().catch(() => {});
    }
  } catch (e) {
    console.warn('[Shutdown] close mongo error:', e?.message || e);
  }

  try {
    gameSessionStore.clear();
  } catch (e) {
    console.warn('[Shutdown] clear game sessions error:', e?.message || e);
  }
}

