// (Removed misplaced adminSocket block)
let mainWindow;
const appLogs = [];
const MAX_LOGS = 200;

const shouldUseSingleInstanceLock = !EARLY_DASHBOARD_MULTI_INSTANCE;
const gotSingleInstanceLock = shouldUseSingleInstanceLock ? app.requestSingleInstanceLock() : true;
if (!gotSingleInstanceLock) {
  writeStartupLog('single-instance-lock denied');
  app.quit();
} else if (shouldUseSingleInstanceLock) {
  app.on('second-instance', () => {
    if (mainWindow && !mainWindow.isDestroyed()) {
      if (mainWindow.isMinimized()) {
        mainWindow.restore();
      }
      mainWindow.show();
      mainWindow.focus();
    }
  });
}

