ipcHandle('get-deposits', async (event, { page = 1, limit = 20, filterType = 'history' } = {}) => {
  const safePage = Math.max(1, Number(page) || 1);
  const safeLimit = Math.min(100, Math.max(1, Number(limit) || 20));
  const normalizedFilter = String(filterType || 'history').trim().toLowerCase();

  let query = {};
  if (normalizedFilter === 'error') query = { status: 2 };
  else if (normalizedFilter === 'history' || normalizedFilter === 'active') query = { status: { $ne: 2 } };

  const skip = (safePage - 1) * safeLimit;
  const total = await Deposit.countDocuments(query);
  const data = await Deposit.find(query).sort({ date: -1 }).skip(skip).limit(safeLimit).lean();
  return { success: true, data, total, totalPages: Math.max(1, Math.ceil(total / safeLimit)) };
});
ipcHandle('get-withdraws', async (event, { page = 1, limit = 20, filterType = 'history' } = {}) => {
  const safePage = Math.max(1, Number(page) || 1);
  const safeLimit = Math.min(100, Math.max(1, Number(limit) || 20));
  const normalizedFilter = String(filterType || 'history').trim().toLowerCase();

  let query = {};
  if (normalizedFilter === 'orders' || normalizedFilter === 'pending') query = { status: 0 };
  else if (normalizedFilter === 'history') query = { status: { $in: [1, 2] } };

  const skip = (safePage - 1) * safeLimit;
  const total = await Withdraw.countDocuments(query);
  const withdraws = await Withdraw.find(query).sort({ date: -1 }).skip(skip).limit(safeLimit).lean();

  const userIds = [...new Set(
    withdraws
      .map((item) => Number(item && item.userId))
      .filter((id) => Number.isFinite(id)),
  )];

  let accountByUser = new Map();
  let depositByUser = new Map();
  let withdrawByUser = new Map();

  if (userIds.length > 0) {
    const [accounts, depositAgg, withdrawAgg] = await Promise.all([
      Account.find({ userId: { $in: userIds } }).select('userId totalBet totalDeposit totalWithdraw').lean(),
      Deposit.aggregate([
        { $match: { userId: { $in: userIds }, status: 1 } },
        { $group: { _id: '$userId', total: { $sum: '$amount' } } },
      ]),
      Withdraw.aggregate([
        { $match: { userId: { $in: userIds }, status: 1 } },
        { $group: { _id: '$userId', total: { $sum: '$amount' } } },
      ]),
    ]);

    accountByUser = new Map((accounts || []).map((acc) => [Number(acc.userId), acc]));
    depositByUser = new Map((depositAgg || []).map((row) => [Number(row._id), Number(row.total || 0)]));
    withdrawByUser = new Map((withdrawAgg || []).map((row) => [Number(row._id), Number(row.total || 0)]));
  }

  const data = withdraws.map((w) => {
    const userId = Number(w && w.userId);
    const acc = accountByUser.get(userId) || {};
    const totalDeposit = depositByUser.has(userId)
      ? Number(depositByUser.get(userId) || 0)
      : Number(acc.totalDeposit || 0);
    const totalWithdraw = withdrawByUser.has(userId)
      ? Number(withdrawByUser.get(userId) || 0)
      : Number(acc.totalWithdraw || 0);
    const totalBet = Number(acc.totalBet || 0);

    return {
      ...w,
      accountStats: {
        totalDeposit,
        totalWithdraw,
        totalBet,
      },
    };
  });

  return { success: true, data, total, totalPages: Math.max(1, Math.ceil(total / safeLimit)) };
});
