ipcHandle('handle-deposit-error', async (event, { id, creditAmount } = {}) => {
  try {
    const deposit = await Deposit.findById(id);
    if (!deposit) return { success: false, message: 'Khong tim thay lenh nap.' };
    if (Number(deposit.status) !== 2) return { success: false, message: 'Lenh nap nay khong o trang thai loi.' };

    const suggestedAmount = Number(deposit.realAmount || deposit.amount || 0);
    const amount = Number.isFinite(Number(creditAmount)) && Number(creditAmount) > 0
      ? Math.floor(Number(creditAmount))
      : Math.floor(suggestedAmount);

    if (!Number.isFinite(amount) || amount <= 0) {
      return { success: false, message: 'So tien duyet tay khong hop le.' };
    }

    const account = await Account.findOne({ userId: deposit.userId });
    if (!account) return { success: false, message: 'Khong tim thay tai khoan nguoi dung.' };

    const oldBalance = Number(account.balance || 0);
    account.balance = oldBalance + amount;
    await account.save();

    deposit.status = 1;
    deposit.realAmount = amount;
    const note = `Duyet tay lenh nap loi (${new Date().toLocaleString('vi-VN')})` ;
    deposit.description = deposit.description ? `${deposit.description} | ${note}` : note;
    await deposit.save();

    await Transaction.create({
      userId: deposit.userId,
      amount,
      action: 'deposit',
      oldBalance,
      newBalance: Number(account.balance || 0),
      description: `Manual deposit approval: ${deposit.requestId || deposit.transId || deposit._id}`
    });

    if (mainBotService && typeof mainBotService.sendNotification === 'function') {
      await mainBotService.sendNotification({
        content:
          `<b>LENH NAP LOI DA DUOC DUYET TAY</b>\n\n` +
          `So tien: <b>${amount.toLocaleString('vi-VN')} VND</b>\n` +
          `Ma lenh: <code>${deposit.requestId || deposit.transId || deposit._id}</code>`,
        targetType: 'user',
        targetValue: deposit.userId,
      });
    }

    return { success: true };
  } catch (error) {
    return { success: false, message: error.message };
  }
});
