ipcHandle('check-main-bot-status', async () => {
  const mainBotConfig = await Bot.findOne({ role: 'main', status: 1 }).lean();
  if (!mainBotConfig) return { success: false, message: 'BOT DANG TAT' };

  if (mainBotService && typeof mainBotService.checkConnection === 'function') {
    return normalizePayload(await mainBotService.checkConnection());
  }

  return { success: true, message: 'BOT DANG CHAY' };
});
