ipcHandle('get-game-stats', async (event, gameType) => {
  try {
    const history = await TxGameHistory.find({ roomType: gameType }).lean();
    const totalProfit = history.reduce((sum, item) => sum + (item.profit || 0), 0);
    const totalGames = history.length;
    const totalBet = history.reduce((sum, item) => sum + (item.realTotalBet || 0), 0);

    const startOfDay = new Date();
    startOfDay.setHours(0, 0, 0, 0);
    const todayHistory = await TxGameHistory.find({ roomType: gameType, date: { $gte: startOfDay } }).lean();
    const todayProfit = todayHistory.reduce((sum, item) => sum + (item.profit || 0), 0);
    const todayBet = todayHistory.reduce((sum, item) => sum + (item.realTotalBet || 0), 0);

    return { success: true, data: { totalProfit, todayProfit, totalGames, totalBet, todayBet } };
  } catch (error) {
    return { success: false, message: error.message };
  }
});

ipcHandle('get-game-history', async (event, { gameType, page = 1, limit = 20 } = {}) => {
  const normalizedGameType = String(gameType || '').trim().toLowerCase();
  const safePage = Math.max(1, Number(page) || 1);
  const safeLimit = Math.min(100, Math.max(1, Number(limit) || 20));
  const skip = (safePage - 1) * safeLimit;
  
  if (['cl_tele', 'tx_tele', 'dice_tele', 'slot_tele'].includes(normalizedGameType)) {
    const total = await MiniGameHistory.countDocuments({ game: normalizedGameType });
    const data = await MiniGameHistory.find({ game: normalizedGameType }).sort({ date: -1 }).skip(skip).limit(safeLimit).lean();
    return { success: true, data, total, totalPages: Math.max(1, Math.ceil(total / safeLimit)) };
  }

  const total = await TxGameHistory.countDocuments({ roomType: normalizedGameType });
  if (total > 0) {
    const data = await TxGameHistory.find({ roomType: normalizedGameType }).sort({ date: -1 }).skip(skip).limit(safeLimit).lean();
    return { success: true, data, total, totalPages: Math.max(1, Math.ceil(total / safeLimit)) };
  }

  const settingModelMap = {
    tx: TxRoomSetting,
    md5: Md5Setting,
    khongminh: KhongMinhSetting,
    taixiucao: TxRoomSetting,
    taixiunan: TxRoomSetting,
    booms: BoomsSetting,
    plinko: PlinkoSetting,
    xeng: XengSetting,
  };

  const SettingModel = settingModelMap[normalizedGameType];
  if (!SettingModel) {
    return { success: true, data: [], total: 0, totalPages: 1 };
  }

  const settingsDoc = await SettingModel.findOne({ roomType: normalizedGameType }, { gameHistory: 1 }).lean();
  const rows = Array.isArray(settingsDoc && settingsDoc.gameHistory) ? settingsDoc.gameHistory : [];
  const ordered = [...rows].sort((a, b) => {
    const da = a && a.date ? new Date(a.date).getTime() : 0;
    const db = b && b.date ? new Date(b.date).getTime() : 0;
    return db - da;
  });
  const totalRows = ordered.length;
  const data = ordered.slice(skip, skip + safeLimit);

  return {
    success: true,
    data,
    total: totalRows,
    totalPages: Math.max(1, Math.ceil(totalRows / safeLimit)),
  };
});
ipcHandle('get-game-player-history', async (event, { gameType, page = 1, limit = 20 } = {}) => {
  try {
    const normalizedGameType = String(gameType || '').trim().toLowerCase();
    const safePage = Math.max(1, Number(page) || 1);
    const safeLimit = Math.min(100, Math.max(1, Number(limit) || 20));
    const skip = (safePage - 1) * safeLimit;

    const miniTotal = await MiniGameHistory.countDocuments({ game: normalizedGameType });
    if (miniTotal > 0) {
      const miniData = await MiniGameHistory.find({ game: normalizedGameType })
        .sort({ date: -1 })
        .skip(skip)
        .limit(safeLimit)
        .lean();
      return {
        success: true,
        data: miniData,
        total: miniTotal,
        totalPages: Math.max(1, Math.ceil(miniTotal / safeLimit)),
      };
    }

    const settingModelMap = {
      tx: TxRoomSetting,
      md5: Md5Setting,
      khongminh: KhongMinhSetting,
      taixiucao: TxRoomSetting,
      taixiunan: TxRoomSetting,
      booms: BoomsSetting,
      plinko: PlinkoSetting,
      xeng: XengSetting,
    };
    const SettingModel = settingModelMap[normalizedGameType];
    if (!SettingModel) {
      return { success: true, data: [], total: 0, totalPages: 1 };
    }

    const settingsDoc = await SettingModel.findOne(
      { roomType: normalizedGameType },
      { gameHistory: 1 },
    ).lean();

    const sessions = Array.isArray(settingsDoc && settingsDoc.gameHistory)
      ? settingsDoc.gameHistory
      : [];
    const playerRows = [];

    const pushRows = (session, sideBets, betType) => {
      if (!Array.isArray(sideBets)) return;
      const resultLower = String(session && session.result ? session.result : '').toLowerCase();
      const isWin = resultLower === String(betType).toLowerCase();
      sideBets.forEach((bet, index) => {
        const amount = Number(bet && bet.amount ? bet.amount : 0);
        if (!Number.isFinite(amount) || amount <= 0) return;
        const userId = String(bet && bet.userId ? bet.userId : '');
        const username = String(bet && bet.username ? bet.username : '');
        const sessionId = session && session.sessionId ? session.sessionId : '';
        const dateValue = session && session.date ? session.date : null;
        playerRows.push({
          id: `${sessionId}-${betType}-${userId || index}-${index}`,
          sessionId,
          date: dateValue,
          userId,
          username: username || (userId ? ('User_' + userId) : 'Unknown'),
          betType,
          betAmount: amount,
          isWin,
          winAmount: null,
        });
      });
    };

    sessions.forEach((session) => {
      pushRows(session, session && session.taiBets, 'Tai');
      pushRows(session, session && session.xiuBets, 'Xiu');
    });

    playerRows.sort((a, b) => {
      const da = a && a.date ? new Date(a.date).getTime() : 0;
      const db = b && b.date ? new Date(b.date).getTime() : 0;
      return db - da;
    });

    const total = playerRows.length;
    const data = playerRows.slice(skip, skip + safeLimit);
    return {
      success: true,
      data,
      total,
      totalPages: Math.max(1, Math.ceil(total / safeLimit)),
    };
  } catch (error) {
    console.error('[Error] get-game-player-history:', error);
    return { success: false, message: error.message, data: [], total: 0, totalPages: 1 };
  }
});
