ipcHandle('get-dashboard-stats', async () => {
  try {
    const totalUsers = await Account.countDocuments({});

    const now = new Date();
    const startOfDay = new Date(now);
    startOfDay.setHours(0, 0, 0, 0);

    const startOfWeek = new Date(startOfDay);
    const dayOfWeek = startOfWeek.getDay();
    const offsetToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
    startOfWeek.setDate(startOfWeek.getDate() - offsetToMonday);

    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);

    const [
      accounts,
      todayNewUsers,
      pendingDeposits,
      pendingWithdraws,
      totalDepositAgg,
      totalWithdrawAgg,
    ] = await Promise.all([
      Account.find({}, 'balance totalBet').lean(),
      Account.countDocuments({ date: { $gte: startOfDay } }),
      Deposit.countDocuments({ status: 0 }),
      Withdraw.countDocuments({ status: 0 }),
      Deposit.aggregate([
        { $match: { status: 1 } },
        { $group: { _id: null, total: { $sum: '$amount' } } },
      ]),
      Withdraw.aggregate([
        { $match: { status: 1 } },
        { $group: { _id: null, total: { $sum: '$amount' } } },
      ]),
    ]);

    const totalBalance = accounts.reduce((sum, acc) => sum + Number(acc && acc.balance ? acc.balance : 0), 0);
    const totalDeposit = Number(totalDepositAgg && totalDepositAgg[0] ? totalDepositAgg[0].total : 0);
    const totalWithdraw = Number(totalWithdrawAgg && totalWithdrawAgg[0] ? totalWithdrawAgg[0].total : 0);

    const historyModels = [
      TxGameHistory,
      Md5History,
      KhongMinhHistory,
      BoomsHistory,
      PlinkoHistory,
      XengHistory,
    ];

    const aggregateHistoryByDate = async (dateFilter = null) => {
      const matchDate = dateFilter ? { date: dateFilter } : {};
      const rows = await Promise.all(historyModels.map((Model) => (
        Model.aggregate([
          { $match: matchDate },
          {
            $group: {
              _id: null,
              totalBet: { $sum: { $ifNull: ['$realTotalBet', '$totalBet'] } },
              totalPayout: { $sum: { $ifNull: ['$totalPayout', 0] } },
              totalProfit: { $sum: { $ifNull: ['$profit', 0] } },
            },
          },
        ])
      )));

      return rows.reduce((acc, row) => {
        const item = row && row[0] ? row[0] : null;
        if (!item) return acc;
        acc.totalBet += Number(item.totalBet || 0);
        acc.totalPayout += Number(item.totalPayout || 0);
        acc.totalProfit += Number(item.totalProfit || 0);
        return acc;
      }, { totalBet: 0, totalPayout: 0, totalProfit: 0 });
    };

    const aggregateMiniByDate = async (dateFilter = null) => {
      const pipeline = [];
      if (dateFilter) pipeline.push({ $match: { date: dateFilter } });
      pipeline.push({
        $group: {
          _id: null,
          totalBet: { $sum: { $ifNull: ['$betAmount', 0] } },
          totalWin: { $sum: { $ifNull: ['$winAmount', 0] } },
        },
      });
      const rows = await MiniGameHistory.aggregate(pipeline);
      const item = rows && rows[0] ? rows[0] : { totalBet: 0, totalWin: 0 };
      return {
        totalBet: Number(item.totalBet || 0),
        totalWin: Number(item.totalWin || 0),
        totalProfit: Number(item.totalBet || 0) - Number(item.totalWin || 0),
      };
    };

    const [
      histAll, histDay, histWeek, histMonth,
      miniAll, miniDay, miniWeek, miniMonth,
    ] = await Promise.all([
      aggregateHistoryByDate(),
      aggregateHistoryByDate({ $gte: startOfDay }),
      aggregateHistoryByDate({ $gte: startOfWeek }),
      aggregateHistoryByDate({ $gte: startOfMonth }),
      aggregateMiniByDate(),
      aggregateMiniByDate({ $gte: startOfDay }),
      aggregateMiniByDate({ $gte: startOfWeek }),
      aggregateMiniByDate({ $gte: startOfMonth }),
    ]);

    const totalBetFromHistory = Number(histAll.totalBet || 0) + Number(miniAll.totalBet || 0);
    const totalWin = Number(histAll.totalPayout || 0) + Number(miniAll.totalWin || 0);
    const totalLose = Math.max(0, totalBetFromHistory - totalWin);

    const profitToday = Number(histDay.totalProfit || 0) + Number(miniDay.totalProfit || 0);
    const profitWeek = Number(histWeek.totalProfit || 0) + Number(miniWeek.totalProfit || 0);
    const profitMonth = Number(histMonth.totalProfit || 0) + Number(miniMonth.totalProfit || 0);

    return {
      success: true,
      data: {
        totalUsers,
        totalBalance,
        todayNewUsers,
        totalDeposit,
        totalWithdraw,
        pendingDeposits,
        pendingWithdraws,
        totalBet: totalBetFromHistory,
        totalWin,
        totalLose,
        profitToday,
        profitWeek,
        profitMonth,
      },
    };
  } catch (error) {
    console.error('[Stats Error]:', error);
    return { success: false, message: error.message };
  }
});

