const resolveLicenseApiCandidates = () => {
  const centerPortValue = Number.parseInt(String(process.env.CENTER_PORT || '').trim(), 10);
  const centerApiPort = String(
    process.env.CENTER_API_PORT
    || (Number.isInteger(centerPortValue) && centerPortValue > 0 ? centerPortValue + 1 : '')
  ).trim();
  const centerApiHost = String(process.env.CENTER_API_HOST || process.env.CENTER_HOST || '').trim();
  const centerWebApiPort = String(process.env.CENTER_WEB_API_PORT || '').trim();
  const centerWebApiHost = String(process.env.CENTER_WEB_API_HOST || process.env.CENTER_WEB_HOST || '').trim();
  const configuredPrimary = String(process.env.CENTER_LICENSE_API_URL || '').trim();
  const configuredLegacy = String(process.env.LICENSE_API_URL || '').trim();
  const candidates = [];
  const seen = new Set();

  const pushCandidate = (rawUrl) => {
    const trimmed = String(rawUrl || '').trim();
    if (!trimmed) return;
    const withProtocol = /^https?:\/\//i.test(trimmed) ? trimmed : 'http://' + trimmed;
    try {
      const parsed = new URL(withProtocol);
      const normalized = parsed.origin.replace(/\/+$/, '');
      if (seen.has(normalized)) return;
      seen.add(normalized);
      candidates.push(normalized);
    } catch (_) {}
  };

  pushCandidate(configuredPrimary);
  pushCandidate(configuredLegacy);
  if (centerApiHost && centerApiPort) {
    pushCandidate('http://' + centerApiHost + ':' + centerApiPort);
  }
  if (centerApiPort) {
    pushCandidate('http://127.0.0.1:' + centerApiPort);
    pushCandidate('http://localhost:' + centerApiPort);
  }
  if (centerWebApiHost && centerWebApiPort) {
    pushCandidate('http://' + centerWebApiHost + ':' + centerWebApiPort);
  }
  if (centerWebApiPort) {
    pushCandidate('http://127.0.0.1:' + centerWebApiPort);
    pushCandidate('http://localhost:' + centerWebApiPort);
  }

  return candidates;
};

ipcHandle('activate-license', async (event, key) => {
  const machineId = getMachineId();
  const apiCandidates = resolveLicenseApiCandidates();

  if (apiCandidates.length === 0) {
    return {
      success: false,
      message: '\u004d\u00e1y ch\u1ee7 k\u00edch ho\u1ea1t ch\u01b0a \u0111\u01b0\u1ee3c c\u1ea5u h\u00ecnh. Vui l\u00f2ng ki\u1ec3m tra CENTER_LICENSE_API_URL, LICENSE_API_URL ho\u1eb7c CENTER_API_HOST/CENTER_API_PORT.',
    };
  }

  const requestBody = JSON.stringify({ key, machineId });
  let lastError = null;

  for (const baseUrl of apiCandidates) {
    const targetUrl = baseUrl + '/api/activate';
    try {
      const response = await fetch(targetUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: requestBody,
      });
      const responseText = await response.text();
      let apiResult = null;

      try {
        apiResult = JSON.parse(responseText);
      } catch (_) {
        console.error('[License API Error] Invalid JSON from', targetUrl, responseText);
        return {
          success: false,
          message: '\u004d\u00e1y ch\u1ee7 k\u00edch ho\u1ea1t tr\u1ea3 v\u1ec1 d\u1eef li\u1ec7u kh\u00f4ng h\u1ee3p l\u1ec7. Vui l\u00f2ng ki\u1ec3m tra Admin Center.',
        };
      }

      if (!response.ok || !apiResult || apiResult.success !== true) {
        return {
          success: false,
          message: apiResult && apiResult.message
            ? apiResult.message
            : '\u004b\u00edch ho\u1ea1t th\u1ea5t b\u1ea1i. Vui l\u00f2ng ki\u1ec3m tra l\u1ea1i m\u00e3 key.',
        };
      }

      return {
        success: true,
        message: apiResult.message || '\u004b\u00edch ho\u1ea1t th\u00e0nh c\u00f4ng!',
        data: apiResult.data || null,
      };
    } catch (error) {
      lastError = error;
      console.error('[License API Error]', targetUrl, error);
    }
  }

  const suffix = lastError && lastError.message ? ' (' + lastError.message + ')' : '';
  return {
    success: false,
    message: '\u004d\u00e1y ch\u1ee7 k\u00edch ho\u1ea1t kh\u00f4ng ph\u1ea3n h\u1ed3i. Vui l\u00f2ng \u0111\u1ea3m b\u1ea3o Admin Center \u0111ang ch\u1ea1y v\u00e0 c\u1ed5ng k\u1ebft n\u1ed1i \u0111\u00e3 m\u1edf' + suffix,
  };
});

