ipcHandle('set-webgame-route', async (event, payload) => {
  try {
    const routeId = payload && payload.id;
    const enabled = !!(payload && payload.enabled);
    const routeExists = WEBGAME_ROUTES.some(r => r.id === routeId);
    if (!routeExists) {
      return { success: false, message: 'Route khong hop le' };
    }

    const settings = await Setting.findOne({}) || await Setting.create({});
    const currentMap = settings.webgameRoutes && typeof settings.webgameRoutes === 'object'
      ? settings.webgameRoutes
      : {};
    settings.webgameRoutes = { ...currentMap, [routeId]: enabled };
    await settings.save();
    return { success: true, data: await getWebgameRouteStatusList() };
  } catch (error) {
    console.error('[Error] set-webgame-route:', error);
    return { success: false, message: error.message };
  }
});

