ipcHandle('get-update-state', async () => {
  const licenseState = await getLicenseUpdateAccessState();
  return {
    success: true,
    data: buildUpdateStatePayload(licenseState),
  };
});

ipcHandle('open-update-page', async () => {
  const licenseAccess = await ensureLicenseAllowsGithubUpdate();
  if (!licenseAccess.allowed) {
    return { success: false, blocked: true, message: licenseAccess.state.licenseUpdateMessage, data: buildUpdateStatePayload(licenseAccess.state) };
  }

  try {
    const url = updateState.releasePage || UPDATER_RELEASE_PAGE;
    if (DASHBOARD_WEB_ONLY) {
      return { success: true, message: 'Dashboard web se mo trang GitHub Releases tren trinh duyet.', url };
    }
    await shell.openExternal(url);
    return { success: true, message: 'Da mo trang tai ban moi.', url };
  } catch (error) {
    return { success: false, message: error.message, url: updateState.releasePage || UPDATER_RELEASE_PAGE };
  }
});

ipcHandle('check-for-updates', async () => {
  const licenseAccess = await ensureLicenseAllowsGithubUpdate();
  if (!licenseAccess.allowed) {
    return { success: false, blocked: true, message: licenseAccess.state.licenseUpdateMessage, data: buildUpdateStatePayload(licenseAccess.state), manual: true };
  }

  if (DASHBOARD_WEB_ONLY) {
    return checkWebOnlyGithubUpdate();
  }

  setupAutoUpdater();

  const enableUpdaterInDev = process.env.ENABLE_UPDATER_IN_DEV === '1' || process.env.FORCE_UPDATER_IN_DEV === '1';
  if (isDev && !enableUpdaterInDev) {
    return {
      success: false,
      message: 'Updater dang tat trong dev. Dat ENABLE_UPDATER_IN_DEV=1 de test.',
      data: buildUpdateStatePayload(),
    };
  }

  if (!canUseNativeAutoUpdater()) {
    const manualMessage = getManualUpdateMessage();
    updateUpdaterState({
      checking: false,
      available: false,
      downloading: false,
      downloaded: false,
      progress: 0,
      error: '',
      message: manualMessage,
      lastCheckedAt: Date.now(),
    });
    return {
      success: true,
      message: manualMessage,
      data: buildUpdateStatePayload(),
      manual: true,
    };
  }

  try {
    const updater = ensureAutoUpdater();
    if (!updater) {
      throw new Error(autoUpdaterInitError || 'Khong khoi tao duoc electron-updater');
    }
    await updater.checkForUpdates();
    return {
      success: true,
      message: 'Da gui yeu cau kiem tra cap nhat.',
      data: buildUpdateStatePayload(),
    };
  } catch (error) {
    const msg = normalizeUpdaterErrorMessage(error);
    updateUpdaterState({
      checking: false,
      downloading: false,
      error: msg,
      message: 'Kiem tra cap nhat that bai: ' + msg,
      lastCheckedAt: Date.now(),
    });
    return {
      success: false,
      message: msg,
      data: buildUpdateStatePayload(),
    };
  }
});

ipcHandle('download-update', async () => {
  const licenseAccess = await ensureLicenseAllowsGithubUpdate();
  if (!licenseAccess.allowed) {
    return { success: false, blocked: true, message: licenseAccess.state.licenseUpdateMessage, data: buildUpdateStatePayload(licenseAccess.state), manual: true };
  }

  if (DASHBOARD_WEB_ONLY) {
    const manualMessage = 'Dashboard web khong tu tai/cai ban moi. Hay pull/build/redeploy tren server, hoac mo GitHub Releases de xem release moi.';
    updateUpdaterState({
      checking: false,
      downloading: false,
      downloaded: false,
      progress: 0,
      error: '',
      message: manualMessage,
      isWebOnly: true,
      manualUpdate: true,
      lastCheckedAt: Date.now(),
    });
    return { success: true, message: manualMessage, manual: true, url: updateState.releasePage || UPDATER_RELEASE_PAGE, data: buildUpdateStatePayload() };
  }

  setupAutoUpdater();

  if (!canUseNativeAutoUpdater()) {
    const manualMessage = getManualUpdateMessage();
    await shell.openExternal(UPDATER_RELEASE_PAGE);
    updateUpdaterState({
      checking: false,
      downloading: false,
      downloaded: false,
      progress: 0,
      error: '',
      message: manualMessage,
      lastCheckedAt: Date.now(),
    });
    return {
      success: true,
      message: manualMessage + ' Da mo trang Releases.',
      isPortable: isPortableBuild(),
      manual: true,
    };
  }

  try {
    updateUpdaterState({
      downloading: true,
      downloaded: false,
      progress: 0,
      message: 'Dang tai ban cap nhat...',
      error: '',
    });
    const updater = ensureAutoUpdater();
    if (!updater) {
      throw new Error(autoUpdaterInitError || 'Khong khoi tao duoc electron-updater');
    }
    await updater.downloadUpdate();
    return { success: true, message: 'Dang tai ban cap nhat...' };
  } catch (error) {
    const msg = normalizeUpdaterErrorMessage(error);
    updateUpdaterState({
      downloading: false,
      error: msg,
      message: 'Tai cap nhat that bai: ' + msg,
    });
    return { success: false, message: msg };
  }
});

ipcHandle('install-update', async () => {
  const licenseAccess = await ensureLicenseAllowsGithubUpdate();
  if (!licenseAccess.allowed) {
    return { success: false, blocked: true, message: licenseAccess.state.licenseUpdateMessage, data: buildUpdateStatePayload(licenseAccess.state), manual: true };
  }

  if (DASHBOARD_WEB_ONLY) {
    const manualMessage = 'Dashboard web khong the tu cai ban moi. Can redeploy tren server sau khi cap nhat source tu GitHub.';
    return { success: true, message: manualMessage, manual: true, url: updateState.releasePage || UPDATER_RELEASE_PAGE, data: buildUpdateStatePayload() };
  }

  if (!canUseNativeAutoUpdater()) {
    const manualMessage = getManualUpdateMessage();
    await shell.openExternal(UPDATER_RELEASE_PAGE);
    return {
      success: true,
      message: manualMessage + ' Da mo trang Releases.',
      isPortable: isPortableBuild(),
      manual: true,
    };
  }

  if (!updateState.downloaded) {
    return { success: false, message: 'Chua tai xong ban cap nhat.' };
  }

  try {
    const updater = ensureAutoUpdater();
    if (!updater) {
      return { success: false, message: autoUpdaterInitError || 'Khong khoi tao duoc electron-updater' };
    }
    setTimeout(() => {
      updater.quitAndInstall(false, true);
    }, 250);
    return { success: true, message: 'Dang cai dat cap nhat va khoi dong lai...' };
  } catch (error) {
    return { success: false, message: error.message };
  }
});
