  expressApp.post('/api/game/trading-order', async (req, res) => {
    try {
      const session = await ensureTradingMarketSession();
      if (typeof session.placeOrder !== 'function') {
        return res.status(503).json({ success: false, message: 'Trading market chua san sang' });
      }

      const userId = resolveGameUserId(req.body || {});
      if (!userId) {
        return res.status(401).json({ success: false, message: 'Khong xac dinh duoc nguoi choi' });
      }

      const sideRaw = String(req.body?.side || req.body?.type || '').trim().toUpperCase();
      if (!['CALL', 'PUT'].includes(sideRaw)) {
        return res.status(400).json({ success: false, message: 'Lenh khong hop le' });
      }

      const amountRaw = Number(req.body?.amount || 0);
      const amount = Number.isFinite(amountRaw) ? Math.floor(amountRaw) : 0;
      if (amount <= 0) {
        return res.status(400).json({ success: false, message: 'So tien lenh khong hop le' });
      }

      const durationRaw = Number(req.body?.durationMs || req.body?.duration || 10000);
      const durationMs = Number.isFinite(durationRaw) ? Math.floor(durationRaw) : 10000;
      const marketId = String(req.body?.marketId || 'okcoin').trim().toLowerCase() || 'okcoin';

      const account = await Account.findOne({ userId });
      if (!account) {
        return res.status(404).json({ success: false, message: 'Khong tim thay tai khoan' });
      }

      const oldBalance = Number(account.balance || 0);
      if (oldBalance < amount) {
        return res.status(400).json({ success: false, message: 'So du khong du' });
      }

      let order = null;
      try {
        order = session.placeOrder({
          userId,
          username: `User_${userId}`,
          side: sideRaw,
          amount,
          durationMs,
          marketId,
        });
      } catch (error) {
        return res.status(400).json({ success: false, message: error.message || 'Khong tao duoc lenh trading' });
      }

      try {
        account.balance = oldBalance - amount;
        await account.save();
      } catch (error) {
        if (order?.orderId && typeof session.cancelOrder === 'function') {
          session.cancelOrder(order.orderId);
        }
        throw error;
      }

      await Transaction.create({
        userId,
        amount,
        action: 'game_bet',
        oldBalance,
        newBalance: Number(account.balance || 0),
        description: `Dat lenh Trading ${sideRaw}`,
      });

      return res.json({
        success: true,
        data: {
          order,
          newBalance: Number(account.balance || 0),
        },
      });
    } catch (error) {
      console.error('[Error] /api/game/trading-order:', error);
      return res.status(500).json({ success: false, message: 'Loi tao lenh trading' });
    }
  });

  expressApp.post('/api/game/trading-order/resolve', async (req, res) => {
    try {
      const session = await ensureTradingMarketSession();
      if (typeof session.resolveOrder !== 'function' || typeof session.getOrder !== 'function') {
        return res.status(503).json({ success: false, message: 'Trading market chua san sang' });
      }

      const userId = resolveGameUserId(req.body || {});
      if (!userId) {
        return res.status(401).json({ success: false, message: 'Khong xac dinh duoc nguoi choi' });
      }

      const orderId = String(req.body?.orderId || '').trim();
      if (!orderId) {
        return res.status(400).json({ success: false, message: 'Thieu ma lenh' });
      }

      const existingOrder = session.getOrder(orderId);
      if (!existingOrder) {
        return res.status(404).json({ success: false, message: 'Khong tim thay lenh' });
      }

      if (Number(existingOrder.userId || 0) !== Number(userId)) {
        return res.status(403).json({ success: false, message: 'Ban khong co quyen xu ly lenh nay' });
      }

      let resolveResult;
      try {
        resolveResult = session.resolveOrder(orderId);
      } catch (error) {
        return res.status(400).json({ success: false, message: error.message || 'Khong the xu ly lenh luc nay' });
      }

      let order = resolveResult?.order || null;
      const account = await Account.findOne({ userId });
      if (!account) {
        return res.status(404).json({ success: false, message: 'Khong tim thay tai khoan' });
      }

      if (order?.isWin && Number(order.payout || 0) > 0 && order.payoutProcessed !== true) {
        const payout = Math.floor(Number(order.payout || 0));
        const oldBalance = Number(account.balance || 0);
        account.balance = oldBalance + payout;
        await account.save();

        if (typeof session.markOrderPayoutProcessed === 'function') {
          order = session.markOrderPayoutProcessed(orderId) || order;
        }

        await Transaction.create({
          userId,
          amount: payout,
          action: 'game_win',
          oldBalance,
          newBalance: Number(account.balance || 0),
          description: `Tra thuong Trading lenh ${orderId}`,
        });
      }

      return res.json({
        success: true,
        data: {
          order,
          newBalance: Number(account.balance || 0),
        },
      });
    } catch (error) {
      console.error('[Error] /api/game/trading-order/resolve:', error);
      return res.status(500).json({ success: false, message: 'Loi xu ly ket qua lenh trading' });
    }
  });
