  expressApp.get('/api/check-cau/history', async (req, res) => {
    try {
      const roomTypeRaw = String(req.query?.roomType || 'tx').trim().toLowerCase();
      const roomType = roomTypeRaw === 'khongminh' ? 'khongminh' : 'tx';
      const limitRaw = Number(req.query?.limit || 60);
      const limit = Number.isFinite(limitRaw)
        ? Math.min(Math.max(Math.floor(limitRaw), 10), 200)
        : 60;

      const Model = getGameModel(roomType);
      const settings = await Model.findOne(
        { roomType },
        { gameHistory: { $slice: limit } },
      ).lean();
      const history = Array.isArray(settings?.gameHistory) ? settings.gameHistory : [];

      const normalized = history
        .map((item) => {
          const row = item && typeof item === 'object' ? item : {};
          const rawDice = Array.isArray(row.dice) ? row.dice : [];
          const dice = [0, 1, 2].map((idx) => {
            const value = Number(rawDice[idx]);
            return Number.isFinite(value) ? value : 0;
          });
          const totalFromDice = dice.reduce((sum, value) => sum + value, 0);
          const totalRaw = Number(row.total);
          const total = Number.isFinite(totalRaw) && totalRaw > 0 ? totalRaw : totalFromDice;
          const sessionId = String(row.sessionId || '');
          const result = String(row.result || '');

          return {
            sessionId,
            result,
            total,
            dice,
            date: row.date || null,
          };
        });

      res.json({ success: true, roomType, data: normalized });
    } catch (error) {
      console.error('[Error] GET /api/check-cau/history:', error);
      res.status(500).json({ success: false, message: error.message, data: [] });
    }
  });
  expressApp.get('/api/check-cau/session', async (req, res) => {
    try {
      const roomTypeRaw = String(req.query?.roomType || 'tx').trim().toLowerCase();
      const roomType = roomTypeRaw === 'khongminh' ? 'khongminh' : 'tx';
      const sessionId = String(req.query?.sessionId || '').trim();
      if (!sessionId) {
        return res.status(400).json({ success: false, message: 'Thieu sessionId' });
      }

      const Model = getGameModel(roomType);
      const settings = await Model.findOne({ roomType }, { gameHistory: 1 }).lean();
      const history = Array.isArray(settings?.gameHistory) ? settings.gameHistory : [];
      const row = history.find((item) => String(item?.sessionId || '') === sessionId);
      if (!row) {
        return res.status(404).json({ success: false, message: 'Khong tim thay phien' });
      }

      const normalizeBetList = (list) => {
        if (!Array.isArray(list)) return [];
        return list
          .map((item) => ({
            userId: String(item?.userId || ''),
            username: String(item?.username || ''),
            amount: Number(item?.amount || 0),
          }))
          .filter((item) => Number.isFinite(item.amount) && item.amount > 0)
          .sort((a, b) => b.amount - a.amount);
      };

      const rawDice = Array.isArray(row?.dice) ? row.dice : [];
      const dice = [0, 1, 2].map((idx) => {
        const value = Number(rawDice[idx]);
        return Number.isFinite(value) ? value : 0;
      });
      const totalFromDice = dice.reduce((sum, value) => sum + value, 0);
      const totalRaw = Number(row?.total);
      const total = Number.isFinite(totalRaw) && totalRaw > 0 ? totalRaw : totalFromDice;
      const taiBets = normalizeBetList(row?.taiBets);
      const xiuBets = normalizeBetList(row?.xiuBets);

      const taiTotalRaw = Number(row?.taiTotal);
      const xiuTotalRaw = Number(row?.xiuTotal);
      const bankerRaw = Number(row?.bankerAmount);

      const taiTotal = Number.isFinite(taiTotalRaw) && taiTotalRaw >= 0
        ? taiTotalRaw
        : taiBets.reduce((sum, item) => sum + Number(item.amount || 0), 0);
      const xiuTotal = Number.isFinite(xiuTotalRaw) && xiuTotalRaw >= 0
        ? xiuTotalRaw
        : xiuBets.reduce((sum, item) => sum + Number(item.amount || 0), 0);
      const bankerAmount = Number.isFinite(bankerRaw) && bankerRaw >= 0 ? bankerRaw : 0;

      return res.json({
        success: true,
        roomType,
        data: {
          sessionId,
          result: String(row?.result || ''),
          total,
          dice,
          taiTotal,
          xiuTotal,
          bankerAmount,
          taiBets,
          xiuBets,
          date: row?.date || null,
        },
      });
    } catch (error) {
      console.error('[Error] GET /api/check-cau/session:', error);
      return res.status(500).json({ success: false, message: error.message });
    }
  });
